mapper.select:
SELECT pp.PLAN_ID AS planId, pp.PLANT_CD AS plantCd, p.PLANT_NM AS plantNm, pp.PLAN_NO AS planNo, pp.PLAN_DT AS planDt, pp.PLAN_TYPE AS planType, pp.ITEM_CD AS itemCd, i.ITEM_NM AS itemNm, pp.PLAN_QTY AS planQty, pp.PLAN_START_DT AS planStartDt, pp.PLAN_END_DT AS planEndDt, pp.PRIORITY AS priority, pp.ORDER_NO AS orderNo, pp.CUSTOMER_CD AS customerCd, pp.CUSTOMER_NM AS customerNm, pp.DELIVERY_DT AS deliveryDt, pp.PLAN_STATUS AS planStatus, pp.RESULT_QTY AS resultQty, pp.PLAN_RMK AS planRmk FROM PLN_PROD_PLAN pp JOIN MST_PLANT p ON p.PLANT_CD = pp.PLANT_CD LEFT JOIN MST_ITEM i ON i.ITEM_CD = pp.ITEM_CD WHERE 1 = 1
AND pp.PLANT_CD = #{plantCd}
AND pp.ITEM_CD = #{itemCd}
AND pp.PLAN_STATUS = #{planStatus}
AND pp.PLAN_DT >= #{planFromDt}
AND pp.PLAN_DT <= #{planToDt}
ORDER BY pp.PLAN_DT DESC, pp.PLAN_ID DESC

mapper.insert:
INSERT INTO PLN_PROD_PLAN (
    PLANT_CD, PLAN_NO, PLAN_DT, PLAN_TYPE, ITEM_CD, PLAN_QTY, PLAN_START_DT, PLAN_END_DT,
    PRIORITY, ORDER_NO, CUSTOMER_CD, CUSTOMER_NM, DELIVERY_DT, PLAN_STATUS, PLAN_RMK, REG_USER_ID
) VALUES (
    #{request.plantCd}, #{request.planNo}, #{request.planDt}, #{request.planType}, #{request.itemCd},
    #{request.planQty}, #{request.planStartDt}, #{request.planEndDt},
    COALESCE(#{request.priority}, 5), #{request.orderNo}, #{request.customerCd}, #{request.customerNm},
    #{request.deliveryDt}, COALESCE(#{request.planStatus}, '계획'), #{request.planRmk}, #{regUserId}
)
